import React, { useState, useEffect } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell
} from 'lucide-react';

const MOCK_USERS_DB = {
  'admin@arconnect.my': { id: 'U001', name: 'Admin AR', email: 'admin@arconnect.my', role: 'admin', plan: 'PRO', credits: 5000, status: 'active', joined: '2023-11-01' },
  'user@gmail.com': { id: 'U002', name: 'ABC Company', email: 'user@gmail.com', role: 'user', plan: 'STARTER', credits: 2000, status: 'active', joined: '2024-01-15' },
  'vip@client.com': { id: 'U003', name: 'VIP Client', email: 'vip@client.com', role: 'user', plan: 'ULTIMATE', credits: 15000, status: 'active', joined: '2024-02-20' },
  'ahmad@marketing.com': { id: 'U004', name: 'Ahmad Marketing', email: 'ahmad@marketing.com', role: 'user', plan: 'STARTER', credits: 50, status: 'suspended', joined: '2024-03-05' },
  'siti@boutique.my': { id: 'U005', name: 'Boutique Siti', email: 'siti@boutique.my', role: 'user', plan: 'PRO', credits: 8400, status: 'active', joined: '2024-04-12' },
};

const PRICING_PLANS = [
  { id: 'starter', name: 'STARTER', price: 'RM49', features: ['2,000 Free Credits', 'Media Support (Image/Video)'], color: 'green' },
  { id: 'pro', name: 'PRO', price: 'RM99', features: ['5,000 Free Credits', 'Anti-Ban System', 'Personalized Messaging'], recommended: true, color: 'green' },
  { id: 'ultimate', name: 'ULTIMATE', price: 'RM179', features: ['12,000 Free Credits', 'Database Support', 'Priority Server Access'], color: 'green' }
];

const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1500, price: 40, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 4000, price: 90, label: 'Pro Reload', icon: Coins, bonus: '+200 Bonus', popular: true },
  { id: 'tu_4', amount: 10000, price: 150, label: 'Enterprise Reload', icon: ShieldCheck, bonus: '+1,000 Bonus' }
];

/* ============================================================================
   ADMIN PORTAL COMPONENT
   ============================================================================ */
const AdminPortal = ({ currentUser, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState(Object.values(MOCK_USERS_DB));
  const [searchQuery, setSearchQuery] = useState('');

  const [editingUser, setEditingUser] = useState(null);
  const [showEditModal, setShowEditModal] = useState(false);
  const [toastMsg, setToastMsg] = useState(null);

  const [editCredits, setEditCredits] = useState(0);
  const [editPlan, setEditPlan] = useState('');
  const [editStatus, setEditStatus] = useState('');

  const showToast = (msg) => {
    setToastMsg(msg);
    setTimeout(() => setToastMsg(null), 3000);
  };

  const openEditModal = (user) => {
    setEditingUser(user);
    setEditCredits(user.credits);
    setEditPlan(user.plan);
    setEditStatus(user.status);
    setShowEditModal(true);
  };

  const closeEditModal = () => {
    setEditingUser(null);
    setShowEditModal(false);
  };

  const handleSaveUser = () => {
    setUsers(users.map(u => {
      if (u.id === editingUser.id) {
        return { ...u, credits: editCredits, plan: editPlan, status: editStatus };
      }
      return u;
    }));
    showToast(`Account ${editingUser.name} updated successfully!`);
    closeEditModal();
  };

  const adjustCredits = (amount) => setEditCredits(prev => Math.max(0, prev + amount));

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    u.email.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const totalCredits = users.reduce((acc, curr) => acc + curr.credits, 0);
  const activeUsersCount = users.filter(u => u.status === 'active').length;

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full">
      {/* Sidebar Admin */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen fixed left-0 top-0">
        <div className="h-20 flex items-center px-6 border-b border-slate-800 bg-slate-950">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white">
              <ShieldAlert size={20} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-white font-black text-lg leading-tight tracking-tight">AR CONNECT</h1>
              <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest">Admin Portal</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <p className="px-4 text-[10px] font-black uppercase tracking-widest text-slate-600 mb-4 mt-4">Menu Utama</p>
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'users', icon: Users, label: 'User Management' },
            { id: 'settings', icon: Settings, label: 'System Settings' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all text-sm ${
                activeTab === item.id 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={18} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 mb-2 bg-slate-800 rounded-xl">
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-white font-bold">AD</div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold text-white truncate">{currentUser.name}</p>
              <p className="text-[10px] text-slate-400 truncate">System Administrator</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-red-400 hover:bg-red-500/10 rounded-xl transition-all">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </aside>

      {/* Main Content Admin */}
      <main className="flex-1 ml-64 flex flex-col h-screen overflow-hidden">
        <header className="h-20 bg-white border-b flex items-center justify-between px-8 sticky top-0 z-10">
          <div><h2 className="text-xl font-black text-slate-800 capitalize">{activeTab === 'users' ? 'User Management' : activeTab}</h2></div>
          <div className="flex items-center gap-4">
            <div className="relative">
              <button className="w-10 h-10 rounded-full border border-slate-200 flex items-center justify-center text-slate-500 hover:bg-slate-50 transition-all">
                <Bell size={18} />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>
            </div>
            <div className="h-8 w-px bg-slate-200"></div>
            <div className="flex items-center gap-2 text-sm font-bold text-emerald-600 bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100">
              <Activity size={16} /> Server Status: Optimal
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8">
          {/* Dashboard Tab */}
          {activeTab === 'dashboard' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <div className="bg-white p-6 rounded-2xl border shadow-sm">
                  <div className="flex items-center justify-between mb-4">
                    <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center"><Users size={24} /></div>
                    <span className="text-xs font-bold text-emerald-500 bg-emerald-50 px-2 py-1 rounded-full">+12%</span>
                  </div>
                  <p className="text-sm font-bold text-slate-400 mb-1">Total Active Users</p>
                  <h3 className="text-3xl font-black text-slate-800">{activeUsersCount}</h3>
                </div>
                <div className="bg-white p-6 rounded-2xl border shadow-sm">
                  <div className="flex items-center justify-between mb-4">
                    <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center"><Database size={24} /></div>
                  </div>
                  <p className="text-sm font-bold text-slate-400 mb-1">Credits in Circulation</p>
                  <h3 className="text-3xl font-black text-slate-800">{totalCredits.toLocaleString()}</h3>
                </div>
                <div className="bg-white p-6 rounded-2xl border shadow-sm">
                  <div className="flex items-center justify-between mb-4">
                    <div className="w-12 h-12 bg-purple-50 text-purple-600 rounded-xl flex items-center justify-center"><MessageSquare size={24} /></div>
                    <span className="text-xs font-bold text-emerald-500 bg-emerald-50 px-2 py-1 rounded-full">+5k today</span>
                  </div>
                  <p className="text-sm font-bold text-slate-400 mb-1">Total Blasts Sent</p>
                  <h3 className="text-3xl font-black text-slate-800">1.2M</h3>
                </div>
                <div className="bg-white p-6 rounded-2xl border shadow-sm">
                  <div className="flex items-center justify-between mb-4">
                    <div className="w-12 h-12 bg-orange-50 text-orange-600 rounded-xl flex items-center justify-center"><Server size={24} /></div>
                  </div>
                  <p className="text-sm font-bold text-slate-400 mb-1">API Server Load</p>
                  <h3 className="text-3xl font-black text-slate-800">24%</h3>
                </div>
              </div>
            </div>
          )}

          {/* Users Tab */}
          {activeTab === 'users' && (
            <div className="bg-white rounded-2xl border shadow-sm overflow-hidden animate-in fade-in duration-500">
              <div className="p-6 border-b flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="relative max-w-md w-full">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    type="text" 
                    placeholder="Search users by name or email..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-emerald-500 font-medium text-sm transition-all"
                  />
                </div>
                <button className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold text-sm hover:bg-slate-800 transition-all flex items-center gap-2">
                  <Plus size={16} /> Add New User
                </button>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider">
                      <th className="p-4 font-black">ID</th>
                      <th className="p-4 font-black">Client Info</th>
                      <th className="p-4 font-black">Plan</th>
                      <th className="p-4 font-black">Credit Balance</th>
                      <th className="p-4 font-black">Status</th>
                      <th className="p-4 font-black text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredUsers.map((user) => (
                      <tr key={user.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="p-4 font-bold text-slate-400 text-sm">{user.id}</td>
                        <td className="p-4">
                          <p className="font-bold text-slate-800 text-sm">{user.name}</p>
                          <p className="text-xs text-slate-500">{user.email}</p>
                        </td>
                        <td className="p-4">
                          <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                            user.plan === 'ULTIMATE' ? 'bg-purple-100 text-purple-700' :
                            user.plan === 'PRO' ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-700'
                          }`}>{user.plan}</span>
                        </td>
                        <td className="p-4">
                          <div className="flex items-center gap-1.5 font-black text-slate-800">
                            <Database size={14} className="text-emerald-500" />
                            {user.credits.toLocaleString()}
                          </div>
                        </td>
                        <td className="p-4">
                          <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold ${
                            user.status === 'active' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'
                          }`}>
                            <div className={`w-1.5 h-1.5 rounded-full ${user.status === 'active' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                            {user.status === 'active' ? 'Active' : 'Suspended'}
                          </span>
                        </td>
                        <td className="p-4 text-right">
                          <button onClick={() => openEditModal(user)} className="inline-flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg text-xs font-bold hover:bg-emerald-50 hover:text-emerald-600 transition-all shadow-sm">
                            <Edit size={14} /> Edit Data
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Admin Modals & Toasts */}
      {showEditModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="bg-slate-900 px-6 py-4 flex items-center justify-between">
              <h3 className="text-white font-black text-lg">Manage User Account</h3>
              <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X size={20} /></button>
            </div>
            <div className="p-6 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-600 uppercase tracking-wide">Subscription Plan</label>
                  <select value={editPlan} onChange={(e) => setEditPlan(e.target.value)} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-800 outline-none">
                    <option value="STARTER">STARTER</option>
                    <option value="PRO">PRO</option>
                    <option value="ULTIMATE">ULTIMATE</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-600 uppercase tracking-wide">Status</label>
                  <select value={editStatus} onChange={(e) => setEditStatus(e.target.value)} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-800 outline-none">
                    <option value="active">Active</option>
                    <option value="suspended">Suspended</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2 pt-4 border-t border-slate-100">
                <label className="text-xs font-bold text-slate-600 uppercase flex justify-between">
                  <span>Credit Balance</span><span className="text-emerald-500 font-black">{editCredits.toLocaleString()} Units</span>
                </label>
                <input type="number" value={editCredits} onChange={(e) => setEditCredits(parseInt(e.target.value) || 0)} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-black text-lg text-slate-800 outline-none" />
              </div>
            </div>
            <div className="p-6 bg-slate-50 border-t border-slate-100 flex gap-3">
              <button onClick={closeEditModal} className="flex-1 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold">Cancel</button>
              <button onClick={handleSaveUser} className="flex-[2] py-3 bg-emerald-500 text-white rounded-xl font-black hover:bg-emerald-600 flex items-center justify-center gap-2"><Save size={18} /> Save</button>
            </div>
          </div>
        </div>
      )}
      {toastMsg && (
        <div className="fixed bottom-6 right-6 bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl z-[200] flex items-center gap-3 animate-in slide-in-from-bottom-5">
          <CheckCircle2 className="text-emerald-500" size={20} />
          <p className="font-bold text-sm">{toastMsg}</p>
        </div>
      )}
    </div>
  );
};


/* ============================================================================
   USER PORTAL COMPONENT
   ============================================================================ */
const UserPortal = ({ currentUser, onLogout }) => {
  const [activeTab, setActiveTab] = useState('blast');
  const [credits, setCredits] = useState(currentUser.credits);
  const [isDeviceLinked, setIsDeviceLinked] = useState(false);
  const [qrStatus, setQrStatus] = useState('idle');
  const [isBlasting, setIsBlasting] = useState(false);
  const [blastProgress, setBlastProgress] = useState(0);
  const [messagesSent, setMessagesSent] = useState(0);
  const [message, setMessage] = useState('');

  const [targetSource, setTargetSource] = useState('csv');
  const [manualNumbers, setManualNumbers] = useState('');
  const [mediaFile, setMediaFile] = useState(null);

  const getTargetCount = () => {
    if (targetSource === 'manual') {
      const numbers = manualNumbers.split(',').map(n => n.trim()).filter(n => n.length > 0);
      return numbers.length || 0;
    }
    return targetSource === 'csv' ? 1000 : 2450;
  };

  const startBlast = () => {
    if (!isDeviceLinked) { setActiveTab('qr'); return; }
    const targetTotal = getTargetCount();
    if (targetTotal === 0 || credits < targetTotal) {
      alert("Invalid targets or insufficient credits."); return;
    }

    setIsBlasting(true); setBlastProgress(0); setMessagesSent(0);
    const interval = setInterval(() => {
      setBlastProgress(prev => {
        const nextProgress = prev + 1;
        const currentSentCount = Math.floor((nextProgress / 100) * targetTotal);
        const prevSentCount = Math.floor((prev / 100) * targetTotal);
        const diff = currentSentCount - prevSentCount;

        if (diff > 0) {
          setMessagesSent(currentSentCount);
          setCredits(c => Math.max(0, c - diff));
        }
        if (nextProgress >= 100) { clearInterval(interval); return 100; }
        return nextProgress;
      });
    }, 50);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-slate-50 text-slate-800 w-full">
      {/* Sidebar User */}
      <aside className="w-full md:w-72 bg-white border-r h-full flex flex-col flex-shrink-0">
        <div className="p-8 flex-grow space-y-6">
          <div className="flex items-center gap-3 mb-10">
            <div className="bg-green-500 p-2 rounded-xl text-white"><Send size={20} fill="currentColor" /></div>
            <span className="text-xl font-black tracking-tight text-slate-900">AR CONNECT</span>
          </div>
          <div className="p-5 bg-slate-900 text-white rounded-[2rem] shadow-xl relative overflow-hidden">
            <p className="text-[10px] font-black opacity-60 uppercase mb-1 tracking-widest">Credit Balance</p>
            <div className="flex items-baseline gap-2">
              <span className="text-3xl font-black">{credits.toLocaleString()}</span>
              <span className="text-xs opacity-50">Units</span>
            </div>
            <button onClick={() => setActiveTab('topup')} className="mt-4 w-full bg-green-500 hover:bg-green-600 text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all">
              <PlusCircle size={14} /> Top Up Credits
            </button>
          </div>
          <nav className="space-y-1">
            {[
              { id: 'blast', label: 'New Blast', icon: Send },
              { id: 'qr', label: 'Link Device', icon: QrCode },
              { id: 'topup', label: 'Buy Credits', icon: ShoppingBag },
              { id: 'history', label: 'Blast History', icon: History },
            ].map((item) => (
              <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-4 p-4 rounded-2xl font-bold transition-all ${activeTab === item.id ? 'bg-green-50 text-green-600' : 'text-slate-500 hover:bg-slate-50'}`}>
                <item.icon size={18} /> <span className="text-xs uppercase tracking-wide">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>
        <div className="p-8 border-t">
          <div className="flex items-center gap-3 mb-6 bg-slate-50 p-3 rounded-2xl">
            <div className="w-10 h-10 bg-white border rounded-xl flex items-center justify-center text-slate-400"><User size={18} /></div>
            <div className="overflow-hidden">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Plan: {currentUser.plan}</p>
              <p className="text-xs font-bold truncate text-slate-800">{currentUser.email}</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-3 p-4 text-red-500 font-black hover:bg-red-50 rounded-2xl transition border border-transparent text-[10px] uppercase tracking-widest">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </aside>

      <main className="flex-grow p-8 md:p-12 overflow-y-auto">
        {/* User Blast Tab */}
        {activeTab === 'blast' && (
          <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
            <div className="flex justify-between items-end mb-10">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight">New Blast Campaign</h2>
                  <p className="text-slate-500 font-medium">Cost: <span className="text-green-600 font-bold">1 Unit</span> / message</p>
                </div>
                <div className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border-2 ${isDeviceLinked ? 'bg-green-50 text-green-600 border-green-100' : 'bg-red-50 text-red-500 border-red-100'}`}>
                  <div className={`w-2 h-2 rounded-full ${isDeviceLinked ? 'bg-green-500' : 'bg-red-500 animate-pulse'}`}></div>
                  {isDeviceLinked ? 'Account Active' : 'No Device Linked'}
                </div>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              <div className="lg:col-span-7 space-y-6">
                <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
                  <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Audience Source</label>
                    <select value={targetSource} onChange={(e) => setTargetSource(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl font-bold text-slate-700 outline-none focus:border-green-500 transition-all">
                      <option value="csv">Import from CSV (1,000 Targets)</option>
                      <option value="db">Returning Customers (2,450 Targets)</option>
                      <option value="manual">Manual Entry</option>
                    </select>
                  </div>
                  <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Message Content</label>
                    <textarea value={message} onChange={(e) => setMessage(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none h-40 font-medium text-slate-700 focus:border-green-500 transition-all" placeholder="Type your WhatsApp message here..." />
                  </div>
                </div>
                <button onClick={startBlast} className="w-full py-6 bg-green-500 text-white rounded-[2.5rem] font-black text-xl hover:bg-green-600 shadow-xl shadow-green-200 transition-all flex items-center justify-center gap-3">
                  <Send size={24} /> START BLAST CAMPAIGN
                </button>
              </div>
              <div className="lg:col-span-5">
                <div className="bg-[#e5ddd5] rounded-[3rem] p-4 shadow-2xl border-[12px] border-slate-900 h-[650px] relative flex flex-col">
                    <div className="bg-[#075e54] text-white p-4 rounded-t-[2rem] -mx-4 -mt-4 flex items-center gap-3 z-10">
                      <div className="w-9 h-9 rounded-full bg-slate-200 flex items-center justify-center overflow-hidden"><User size={20} className="text-slate-400 mt-2" /></div>
                      <div><p className="text-xs font-bold">Customer Preview</p><p className="text-[9px] opacity-70">online</p></div>
                    </div>
                    <div className="mt-6 flex-grow overflow-y-auto pr-2 pb-10">
                      <div className="bg-white p-2 rounded-2xl rounded-tl-none shadow-sm max-w-[85%] text-sm">
                        <div className="p-2 whitespace-pre-wrap">{message || <span className="text-slate-400 italic">Type a message...</span>}</div>
                      </div>
                    </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* User QR Tab */}
        {activeTab === 'qr' && (
          <div className="max-w-4xl mx-auto flex flex-col items-center justify-center py-20 text-center">
              <div className="w-64 h-64 bg-white p-6 rounded-[3rem] shadow-xl border-4 border-slate-100 flex items-center justify-center mb-10">
                {qrStatus === 'linked' ? (
                  <div className="text-green-500 flex flex-col items-center gap-4 animate-in zoom-in duration-300">
                    <CheckCircle2 size={80} /><p className="text-xs font-black uppercase tracking-widest">Device Linked</p>
                  </div>
                ) : (
                  <div className="flex flex-col items-center gap-4">
                    <QrCode size={80} className="text-slate-100" /><p className="text-xs font-bold text-slate-300">SCAN QR CODE</p>
                  </div>
                )}
              </div>
              <h3 className="text-3xl font-black mb-4">Link Your WhatsApp</h3>
              <p className="text-slate-500 mb-8 max-w-sm">Scan the QR code to connect your business WhatsApp account.</p>
              <button onClick={() => { setQrStatus('linked'); setIsDeviceLinked(true); }} className="bg-green-500 text-white px-10 py-4 rounded-2xl font-black hover:bg-green-600 transition shadow-lg shadow-green-100 uppercase tracking-widest text-xs">
                GENERATE QR CODE NOW
              </button>
          </div>
        )}

        {/* User Topup Tab */}
        {activeTab === 'topup' && (
          <div className="max-w-5xl mx-auto">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {TOPUP_PACKAGES.map((pkg) => (
                <div key={pkg.id} className="bg-white p-8 rounded-[2.5rem] border-2 border-slate-100 hover:shadow-xl transition-all">
                  <div className="bg-slate-50 w-12 h-12 rounded-2xl flex items-center justify-center text-slate-900 mb-6"><pkg.icon size={24} /></div>
                  <h4 className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-1">{pkg.label}</h4>
                  <div className="text-4xl font-black text-slate-900 mb-4">{pkg.amount.toLocaleString()}</div>
                  <button onClick={() => setCredits(c => c + pkg.amount)} className="w-full py-3.5 rounded-xl font-black text-[10px] uppercase tracking-widest bg-slate-900 text-white hover:bg-green-500 transition-all">
                    Buy Credits
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {/* Blasting Progress Overlay */}
      {isBlasting && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[3rem] p-12 text-center shadow-2xl">
            <div className={`w-28 h-28 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner ${blastProgress < 100 ? 'bg-green-50 text-green-500' : 'bg-green-500 text-white'}`}>
              {blastProgress < 100 ? <Loader2 size={56} className="animate-spin" /> : <CheckCircle2 size={56} />}
            </div>
            <h3 className="text-4xl font-black mb-2">{blastProgress < 100 ? 'Processing...' : 'Completed!'}</h3>
            <div className="mb-6 h-5 bg-slate-100 rounded-full overflow-hidden p-1">
               <div className="h-full bg-green-500 rounded-full transition-all duration-300" style={{ width: `${blastProgress}%` }}></div>
            </div>
            {blastProgress === 100 && <button onClick={()=>setIsBlasting(false)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase">Return</button>}
          </div>
        </div>
      )}
    </div>
  );
};


/* ============================================================================
   MAIN APP (ROUTER & LANDING PAGE)
   ============================================================================ */
export default function App() {
  const [view, setView] = useState('landing'); // 'landing', 'admin', 'user'
  const [currentUser, setCurrentUser] = useState(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [loginEmail, setLoginEmail] = useState('');

  const handleLogin = (e) => {
    e.preventDefault();
    const userAccount = MOCK_USERS_DB[loginEmail] || { 
      name: loginEmail.split('@')[0], 
      email: loginEmail, 
      role: 'user', // Default to normal user if not found in mock DB
      plan: 'FREE', 
      credits: 100 
    };

    setCurrentUser(userAccount);
    setShowLoginModal(false);

    // RBAC Routing based on user role
    if (userAccount.role === 'admin') {
      setView('admin');
    } else {
      setView('user');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setView('landing');
  };

  // Route handling
  if (view === 'admin') return <AdminPortal currentUser={currentUser} onLogout={handleLogout} />;
  if (view === 'user') return <UserPortal currentUser={currentUser} onLogout={handleLogout} />;

  // Default Landing Page View
  return (
    <div className="min-h-screen bg-white font-sans text-slate-800">
      <nav className="bg-white/90 backdrop-blur-md border-b sticky top-0 z-50 px-6 h-20 flex justify-between items-center max-w-7xl mx-auto">
        <div className="flex items-center gap-3">
          <div className="bg-green-500 p-2 rounded-xl text-white"><Send size={20} fill="currentColor" /></div>
          <span className="text-2xl font-black tracking-tighter">AR CONNECT</span>
        </div>
        <button onClick={() => setShowLoginModal(true)} className="bg-slate-900 text-white px-8 py-3 rounded-2xl font-black hover:bg-slate-800 transition text-xs uppercase tracking-widest">
          Login Portal
        </button>
      </nav>

      <section className="pt-24 pb-12 px-4 text-center max-w-4xl mx-auto">
        <p className="text-green-600 font-bold tracking-[0.2em] text-xs uppercase mb-4">Unified Marketing System</p>
        <h1 className="text-5xl md:text-7xl font-black text-slate-900 mb-6 tracking-tight">AR <span className="text-green-600">CONNECT</span></h1>
        <p className="text-slate-500 text-lg max-w-2xl mx-auto mb-10 leading-relaxed">
          The #1 WhatsApp Blast System. Reach your customers instantly with our best-in-class anti-ban technology.
        </p>
        <button onClick={() => setShowLoginModal(true)} className="bg-green-500 text-white px-10 py-5 rounded-[2rem] font-black hover:bg-green-600 transition shadow-xl text-lg">
          Log Masuk Sistem
        </button>
      </section>

      {/* Login Modal */}
      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-300">
             <div className="text-center mb-10">
               <div className="bg-green-500 w-16 h-16 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-lg shadow-green-100"><Lock size={32} /></div>
               <h3 className="text-3xl font-black">Portal Log Masuk</h3>
               <p className="text-slate-400 text-sm font-medium mt-2">Log in sebagai <b>admin@arconnect.my</b> (Admin) atau <b>user@gmail.com</b> (Klien).</p>
             </div>
             <form onSubmit={handleLogin} className="space-y-4">
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Account Email</label>
                 <input type="email" value={loginEmail} onChange={(e)=>setLoginEmail(e.target.value)} placeholder="e.g. admin@arconnect.my" required className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" />
               </div>
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
                 <input type="password" placeholder="••••••••" required className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" />
               </div>
               <button type="submit" className="w-full py-5 bg-green-500 text-white rounded-2xl font-black hover:bg-green-600 transition shadow-xl shadow-green-100 mt-4 uppercase tracking-widest">Login</button>
             </form>
             <button onClick={()=>setShowLoginModal(false)} className="w-full mt-6 py-2 text-slate-400 text-xs font-bold uppercase tracking-widest hover:text-slate-600">Cancel</button>
          </div>
        </div>
      )}
    </div>
  );
}
